const rawInput = $input.first().json;
const input = rawInput.body || rawInput;

let phone, userText, userName, chatId, channel, externalMessageId;
let contentType = 'text';
let mediaInfo = null;

const capitalize = (s) => s ? s.charAt(0).toUpperCase() + s.slice(1).toLowerCase() : '';

// === CHAT TRIGGER (test) ===
if (input.chatInput !== undefined) {
  phone = 'test_' + (input.sessionId || 'default');
  userText = input.chatInput;
  userName = 'Test User';
  chatId = phone;
  channel = 'chat';
  externalMessageId = 'chat_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
}
// === TELEGRAM TRIGGER ===
else if (input.message && input.message.from) {
  const msg = input.message;
  phone = 'tg_' + msg.from.id.toString();

  const firstName = capitalize(msg.from.first_name || '');
  const lastName = capitalize(msg.from.last_name || '');
  userName = (firstName + (lastName ? ' ' + lastName : '')).trim();
  if (!userName) userName = msg.from.username || 'TG User';

  chatId = msg.from.id.toString();
  channel = 'telegram';
  externalMessageId = 'tg_' + msg.chat.id + '_' + msg.message_id;

  if (msg.photo && msg.photo.length > 0) {
    contentType = 'photo';
    const largest = msg.photo[msg.photo.length - 1];
    mediaInfo = {
      file_id: largest.file_id,
      file_unique_id: largest.file_unique_id,
      width: largest.width,
      height: largest.height,
      file_size: largest.file_size
    };
    userText = msg.caption || '[photo received]';
  }
  else if (msg.voice) { contentType = 'voice'; userText = '[voice message]'; mediaInfo = { file_id: msg.voice.file_id }; }
  else if (msg.video) { contentType = 'video'; userText = msg.caption || '[video]'; mediaInfo = { file_id: msg.video.file_id }; }
  else if (msg.document) { contentType = 'document'; userText = '[document: ' + (msg.document.file_name || 'file') + ']'; mediaInfo = { file_id: msg.document.file_id }; }
  else if (msg.sticker) { contentType = 'sticker'; userText = msg.sticker.emoji || '[sticker]'; }
  else if (msg.text) {
    contentType = 'text';
    userText = msg.text;
  } else {
    return null;
  }
}
// === WAZZUP WEBHOOK ===
else if (input.messages && Array.isArray(input.messages) && input.messages.length > 0) {
  const msg = input.messages[0];

  if (msg.isEcho === true) {
    console.log('[Normalize] Skipping echo message (sent from phone)');
    return null;
  }

  if (msg.status && msg.status !== 'inbound') {
    return null;
  }

  if (msg.chatType && msg.chatType !== 'whatsapp') {
    return null;
  }

  phone = 'wa_' + (msg.chatId || '').replace(/\D/g, '');

  const rawName = (msg.contact && msg.contact.name) ? msg.contact.name : '';
  userName = rawName.split(' ').map(w => capitalize(w)).join(' ') || 'WA Lead';

  chatId = (msg.chatId || '').replace(/\D/g, '');
  channel = 'whatsapp';
  externalMessageId = 'wa_' + (msg.messageId || (chatId + '_' + Date.now()));

  if (msg.type === 'image') {
    contentType = 'photo';
    mediaInfo = { content_uri: msg.contentUri, message_id: msg.messageId };
    userText = msg.text || '[photo received]';
  }
  else if (msg.type === 'audio') {
    contentType = 'voice';
    userText = '[voice message]';
    mediaInfo = { content_uri: msg.contentUri, message_id: msg.messageId };
  }
  else if (msg.type === 'video') {
    contentType = 'video';
    userText = msg.text || '[video]';
    mediaInfo = { content_uri: msg.contentUri, message_id: msg.messageId };
  }
  else if (msg.type === 'document') {
    contentType = 'document';
    userText = '[document]';
    mediaInfo = { content_uri: msg.contentUri, message_id: msg.messageId };
  }
  else if (msg.type === 'text') {
    contentType = 'text';
    userText = msg.text || '';
  }
  else {
    return null;
  }
}
else {
  return null;
}

if (!userText || userText.trim().length === 0) return null;

return [{
  json: {
    phone, chat_id: chatId, channel,
    user_text: userText.trim(),
    user_name: userName || '',
    external_message_id: externalMessageId,
    received_at: new Date().toISOString(),
    content_type: contentType,
    media_info: mediaInfo
  }
}];

// Build storage path for photo (works for both TG and WA)
const norm = $('Normalize payload').first().json;
const timestamp = Date.now();
const safeMsgId = norm.external_message_id.replace(/[^a-z0-9_]/gi, '_');
const storagePath = `${norm.phone}/${timestamp}_${safeMsgId}.jpg`;

return [{
  json: {
    phone: norm.phone,
    channel: norm.channel,
    external_message_id: norm.external_message_id,
    file_id: norm.media_info?.file_id,
    file_size: norm.media_info?.file_size || 0,
    storage_path: storagePath,
    storage_bucket: 'lead-photos'
  },
  binary: $input.first().binary
}];

const rows = $input.all().map(i => i.json);
const norm = $('Normalize payload').first().json;
if (rows.length === 0) return null;
const lastExternalId = rows[rows.length - 1].external_message_id;
if (lastExternalId !== norm.external_message_id) return null;
const combinedText = rows.map(r => r.text).join('\n');
return [{
  json: {
    ...norm,
    user_text: combinedText,
    debounced_count: rows.length
  }
}];

const row = $('Load lead profile').first().json;
const norm = $('Debounce decide').first().json;

// Check for unsupported media types
const contentType = $('Normalize payload').first().json.content_type || 'text';
const isUnsupportedMedia = ['voice', 'video', 'document', 'sticker'].includes(contentType);
const isVoice = contentType === 'voice';

let manualActive = false, dnc = false;
let autoBlockSpam = false, autoBlockEscort = false, autoLowBudget = false;

if (row) {
  if (row.do_not_contact === true) dnc = true;
  if (row.mode === 'manual' && row.manual_until) {
    if (new Date(row.manual_until) > new Date()) manualActive = true;
  }
}

// AUTO-CHECKS:
// 1. SPAM: >30 inbound сообщений за 24h
const msgCount24h = parseInt(row.msg_count_24h || 0);
if (msgCount24h > 30 && !dnc) {
  autoBlockSpam = true;
}

// 2. ESCORT: 2-й раз спрашивает про эскорт
const userText = (norm.user_text || '').toLowerCase();
const isEscortMention = /escort|sexo|sexual|prostit|acompañante|servicio sexual/i.test(userText);
const escortCount = parseInt(row.escort_mention_count || 0);
if (isEscortMention && escortCount >= 1) {
  // 2-й раз (1-й уже сосчитан в БД)
  autoBlockEscort = true;
}

// 3. LOW BUDGET: если budget_signal=low → курс автомат
// (срабатывает при первом обнаружении low)
if (row.budget_signal === 'low' && row.funnel_stage !== 'lost') {
  autoLowBudget = true;
}

return [{
  json: {
    ...norm,
    manualActive, dnc,
    isUnsupportedMedia, isVoice, contentType,
    skipAI: manualActive || dnc || autoBlockSpam || autoBlockEscort || autoLowBudget || isUnsupportedMedia,
    autoBlockSpam, autoBlockEscort, autoLowBudget,
    isEscortMention,
    msgCount24h,
    leadProfile: {
      funnel_stage: row.funnel_stage || 'new',
      age: row.age || null,
      profession: row.profession || null,
      is_single: row.is_single,
      budget_signal: row.budget_signal || null,
      interest: row.interest || null,
      photo_received: row.photo_received || false,
      objection_count: row.objection_count || 0,
      last_objection_type: row.last_objection_type || null,
      msg_count_24h: msgCount24h,
      escort_mention_count: escortCount
    }
  }
}];

