let data;
try {
  const text = $json.output || $json.text || '';
  const m = text.match(/\{[\s\S]*\}/);
  data = m ? JSON.parse(m[0]) : { send_invitation_image: send_inv,
    reply_messages: [text] };
} catch(e) {
  data = { reply_messages: ['Un momento, te respondo pronto 😊'] };
}

const norm = $('Debounce decide').first().json;
const profile = $('Evaluate context').first().json.leadProfile;

// Очистка артефактов
const cleanArtifacts = (text) => {
  if (!text) return '';
  return text
    .replace(/\[Citation\]\([^)]*\)/gi, '')
    .replace(/\[citation_marker[^\]]*\]/gi, '')
    .replace(/citation_marker\/?\?[^\s]*/gi, '')
    .replace(/\[\d+\]/g, '')
    .replace(/\(message_idx=\d+[^)]*\)/gi, '')
    .replace(/\s+\./g, '.')
    .replace(/\s+,/g, ',')
    .replace(/\s{2,}/g, ' ')
    .trim();
};

let messages = (data.reply_messages || [])
  .filter(m => typeof m === 'string')
  .map(m => cleanArtifacts(m))
  .map(m => m.replace(/[*_~`]+/g, '').replace(/^\s*\d+[.\)]\s*/gm, '').trim())
  .filter(m => m.length > 0);

if (messages.length === 0) messages = ['Un momento, te respondo pronto 😊'];
if (messages.length > 4) messages = messages.slice(0, 4);

const t = (norm.user_text || '').toLowerCase();
let forceEscalate = false, forceReason = null;

if (/escort|sexo|sexual|acompañante|prostit/i.test(t)) { forceEscalate = true; forceReason = 'Спрашивает про эскорт'; }
if (/descuento|rebaja|cupón|cupon|menos.*precio/i.test(t)) { forceEscalate = true; forceReason = 'Просит скидку'; }
if (/(devolver|reembolso|refund)/i.test(t)) { forceEscalate = true; forceReason = 'Просит возврат'; }
if (/(quiero pagar|cómo pago|cuenta bancaria|listo para pagar|datos bancarios|pagué|ya pague|ya pagué|transferí|envié.*dinero|hice.*pago|pague.*enlace|pague.*link)/i.test(t)) { forceEscalate = true; forceReason = 'Готов оплатить'; }
if (/(idiota|estúpido|pendej|mierda|cabrón|estafa|fraude)/i.test(t)) { forceEscalate = true; forceReason = 'Агрессивное поведение'; }
if (/(traer.*amigo|llevar.*amigo|venir.*amigo|amigo.*venir|amigo.*evento|mi amigo|puedo treat.*amigo)/i.test(t)) { forceEscalate = true; forceReason = 'Хочет привести друга'; }
if (/(no.*lleg.*boleto|no.*recib.*boleto|no.*lleg.*correo|donde.*boleto|ticket.*not.*receive)/i.test(t)) { forceEscalate = true; forceReason = 'Билет не пришёл'; }

let escalate = data.escalate_to_human === true;
let reason = data.escalation_reason || null;
if (forceEscalate) { escalate = true; if (!reason) reason = forceReason; }

if (reason) {
  const r = reason.toLowerCase();
  if (r.includes('descuento')) reason = 'Просит скидку';
  else if (r.includes('insist') || r.includes('настаива')) reason = 'Настаивает на эскорте';
  else if (r.includes('escort') || r.includes('эскорт')) reason = 'Спрашивает про эскорт';
  else if (r.includes('amigo') || r.includes('friend')) reason = 'Хочет привести друга';
  else if (r.includes('agresiv')) reason = 'Агрессивное поведение';
  else if (r.includes('boleto') || r.includes('ticket')) reason = 'Билет не пришёл';
  else if (r.includes('refund') || r.includes('devol')) reason = 'Просит возврат';
  else if (r.includes('pago') || r.includes('оплат')) reason = 'Готов оплатить';
}

const updates = data.update_fields || {};
const funnelStage = data.funnel_stage || profile.funnel_stage || 'new';


// === SEND INVITATION IMAGE FLAG ===
let send_inv = false;
try {
  if (parsed && parsed.send_invitation_image === true) {
    send_inv = true;
  } else if (typeof rawText === 'string' && /send_invitation_image\s*[:=]\s*true/i.test(rawText)) {
    send_inv = true;
  }
} catch(e) {}


return [{
  json: {
    phone: norm.phone,
    chat_id: norm.chat_id,
    channel: norm.channel,
    user_name: norm.user_name,
    user_text: norm.user_text,
    reply_messages: messages,
    escalate,
    escalation_reason: reason,
    funnel_stage: funnelStage,
    update_fields: {
      age: updates.age || null,
      profession: updates.profession || null,
      is_single: updates.is_single,
      budget_signal: updates.budget_signal || null,
      interest: updates.interest || null
    },
    leadProfile: profile
  }
}];

const data = $input.first().json;
const sets = [];
if (data.funnel_stage) sets.push(`funnel_stage = '${data.funnel_stage.replace(/'/g, "''")}'`);
const u = data.update_fields || {};
if (u.age !== null && Number.isInteger(u.age)) sets.push(`age = ${u.age}`);
if (u.profession) sets.push(`profession = $$${u.profession}$$`);
if (u.is_single !== null && u.is_single !== undefined) sets.push(`is_single = ${u.is_single ? 'true' : 'false'}`);
if (u.budget_signal && ['low','medium','high'].includes(u.budget_signal)) sets.push(`budget_signal = '${u.budget_signal}'`);
if (u.interest && ['event','agency','both'].includes(u.interest)) sets.push(`interest = '${u.interest}'`);

// === NEW AGENCY QUESTIONNAIRE FIELDS ===
if (u.first_name) sets.push(`name = $$${u.first_name}$$`);
if (u.last_name) sets.push(`last_name = $$${u.last_name}$$`);
if (u.email) {
  // Validate email format
  const emailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(u.email);
  if (emailValid) sets.push(`email = $$${u.email}$$`);
}
if (u.date_of_birth) {
  // Validate YYYY-MM-DD format
  if (/^\d{4}-\d{2}-\d{2}$/.test(u.date_of_birth)) {
    sets.push(`date_of_birth = '${u.date_of_birth}'::date`);
  }
}
if (u.city) sets.push(`city = $$${u.city}$$`);
if (u.country) sets.push(`country = $$${u.country}$$`);
if (u.marital_status && ['single','divorced','widower','married'].includes(u.marital_status)) {
  sets.push(`marital_status = '${u.marital_status}'`);
  // Sync с is_single для backward compatibility
  if (u.marital_status === 'single') sets.push('is_single = true');
  else if (['divorced','widower','married'].includes(u.marital_status)) sets.push('is_single = false');
}
if (u.business_link) sets.push(`business_link = $$${u.business_link}$$`);
if (u.desired_partner_age) sets.push(`desired_partner_age = $$${u.desired_partner_age}$$`);
if (u.selected_service && ['event','agency','both'].includes(u.selected_service)) {
  sets.push(`selected_service = '${u.selected_service}'`);
  // Map к interest
  if (u.selected_service === 'event') sets.push(`interest = 'event'`);
  else if (u.selected_service === 'agency') sets.push(`interest = 'agency'`);
  else if (u.selected_service === 'both') sets.push(`interest = 'both'`);
}

sets.push('last_ai_message_at = now()');
sets.push('updated_at = now()');
if (['new','pitched','qualified','event_interested','agency_interested'].includes(data.funnel_stage)) {
  sets.push(`next_followup_at = now() + interval '24 hours'`);
}
if (data.funnel_stage === 'lost' || data.funnel_stage === 'rejected_filter') sets.push(`next_followup_at = NULL`);

const sql = `UPDATE leads SET ${sets.join(', ')} WHERE phone = '${data.phone}';`;
return [{ json: { ...data, sql } }];

const parseData = $('Parse output + anti-repeat').first().json;
const ctxData = $input.first().json || {};

// Эмодзи и описание на человеческом языке (не funnel-термины!)
const funnelLabels = {
  'new': '🆕 Только пришёл',
  'pitched': '💬 Я ему рассказала про продукты',
  'qualified': '✅ Узнала возраст/работу/семейный статус',
  'event_interested': '🎉 Хочет на вечеринку',
  'agency_interested': '💎 Хочет агентство',
  'ready_to_pay': '💳 Готов платить',
  'paid_event': '✨ Оплатил вечеринку',
  'paid_agency': '💎 Оплатил агентство',
  'rejected_filter': '🚫 Не прошёл фильтры',
  'lost': '❌ Слился'
};
const reasonEmoji = {
  'Готов оплатить': '💳',
  'Просит скидку': '💰',
  'Спрашивает про эскорт': '⛔',
  'Настаивает на эскорте': '⛔⛔',
  'Хочет привести друга': '👥',
  'Билет не пришёл': '🎫',
  'Просит возврат': '↩️',
  'Юридический вопрос': '⚖️',
  'Агрессивное поведение': '⚠️',
  'Жалоба': '😡'
};
const budgetLabels = { 'low': 'низкий 💵', 'medium': 'средний 💵💵', 'high': 'высокий 💵💵💵' };

const reason = parseData.escalation_reason || 'Нужна помощь';
const emoji = reasonEmoji[reason] || '🚨';
const funnelLabel = funnelLabels[parseData.funnel_stage] || parseData.funnel_stage;

const username = parseData.user_name || ctxData.whatsapp_name || '(без имени)';
const phone = parseData.phone || '';
const cleanPhone = phone.replace('wa_', '').replace('+', '');
const contactLink = `https://wa.me/${cleanPhone}`;
const linkLabel = '💬 Открыть чат в WhatsApp';

const age = ctxData.age || parseData.update_fields?.age;
const profession = ctxData.profession || parseData.update_fields?.profession;
const budget = ctxData.budget_signal || parseData.update_fields?.budget_signal;
const interest = ctxData.interest || parseData.update_fields?.interest;
const msgCount = ctxData.msg_count || 0;
const objCount = ctxData.objection_count || 0;

let text = `${emoji} ${reason.toUpperCase()}\n`;
text += `━━━━━━━━━━━\n\n`;
text += `👤 ${username}\n`;
text += `📞 ${cleanPhone}\n`;
text += `📊 ${funnelLabel}\n`;

if (profession || age) {
  text += `💼 `;
  if (profession) text += profession;
  if (age) text += (profession ? ', ' : '') + age + ' лет';
  text += `\n`;
}
if (budget) text += `💰 Бюджет: ${budgetLabels[budget] || budget}\n`;
if (interest === 'event') text += `🎯 Хочет: на вечеринку\n`;
else if (interest === 'agency') text += `🎯 Хочет: матчмейкинг\n`;
else if (interest === 'both') text += `🎯 Хочет: и то и другое\n`;
if (msgCount > 0) text += `💬 Сообщений всего: ${msgCount}\n`;
if (objCount > 0) text += `🛡️ Возражений: ${objCount}\n`;

text += `\n📝 ЛИД НАПИСАЛ:\n«${(parseData.user_text || '').substring(0, 250)}»\n\n`;

if (parseData.reply_messages && parseData.reply_messages.length > 0) {
  text += `🤖 Я ОТВЕТИЛА:\n`;
  parseData.reply_messages.forEach((m, i) => {
    text += `${i+1}. ${(m || '').substring(0, 180)}\n`;
  });
  text += `\n`;
}
text += `⏱ Я остановилась на 4 часа. Возьми диалог в свои руки или верни мне через кнопку.`;

return [{
  json: {
    phone: phone,
    escalation_reason: parseData.escalation_reason,
    formatted_text: text,
    contact_link: contactLink,
    contact_label: linkLabel
  }
}];

const base = $('Parse output + anti-repeat').first().json;
const messages = base.reply_messages || [];
return messages.map((msg, i) => {
  const baseDelay = Math.max(2, Math.min(8, msg.length / 25));
  const randomExtra = 1.5 + Math.random() * 2;
  const typingDelay = Math.round((baseDelay + randomExtra) * 10) / 10;
  return {
    json: {
      phone: base.phone,
      chat_id: base.chat_id,
      channel: base.channel,
      text: msg,
      sequence_index: i,
      is_last: i === messages.length - 1,
      typing_delay_sec: typingDelay
    }
  };
});

// Vision parser — handles profile photos AND payment receipts
const inputJson = $input.first().json;

let out = inputJson;
if (Array.isArray(out)) out = out[0];
if (Array.isArray(out)) out = out[0];

let rawText = '';
if (out?.content?.[0]?.text) rawText = out.content[0].text;
else if (out?.text) rawText = out.text;
else if (out?.output) rawText = out.output;
else if (out?.message?.content) rawText = out.message.content;

console.log('[Vision] rawText length:', rawText.length);

let visionData = { verdict: 'manual_review', score: 5, reasons: [], image_type: 'other' };

if (rawText) {
  try {
    let clean = rawText.trim();
    clean = clean.replace(/^```json/i, '').replace(/^```/, '').replace(/```$/, '').trim();
    const firstBrace = clean.indexOf('{');
    const lastBrace = clean.lastIndexOf('}');
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      visionData = JSON.parse(clean.substring(firstBrace, lastBrace + 1));
      console.log('[Vision] PARSED:', JSON.stringify(visionData));
    }
  } catch(e) {
    console.log('[Vision] parse error:', e.message);
  }
}

