// Format last 20 messages for AI Agent prompt
const rows = $input.all().map(i => i.json).filter(r => r.text);

if (rows.length === 0) {
  return [{ json: { history_text: '(нет предыдущих сообщений)', message_count: 0 } }];
}

// Сортируем по времени (от старых к новым) — БД дала DESC, разворачиваем
rows.reverse();

const lines = rows.map(r => {
  const who = r.direction === 'inbound' ? 'LEAD' : 'ANNA';
  const text = (r.text || '').substring(0, 200);
  return `${who}: ${text}`;
});

const history_text = lines.join('\n');
const message_count = rows.length;

// Также собираем уже отправленные ссылки (anti-repeat)
const linkPattern = /(https?:\/\/[^\s]+)/g;
const annaMessages = rows.filter(r => r.direction === 'outbound');
const linksSet = new Set();
annaMessages.forEach(m => {
  const matches = (m.text || '').match(linkPattern);
  if (matches) matches.forEach(l => linksSet.add(l));
});
const links_sent = Array.from(linksSet);

return [{
  json: {
    history_text,
    message_count,
    anna_messages_count: annaMessages.length,
    links_sent
  }
}];

